import{c as o,Q as e,j as d,m as a}from"./chunks/framework.Bhbi9jCp.js";const p=JSON.parse('{"title":"AI 学习路线总览","description":"","frontmatter":{},"headers":[],"relativePath":"aiLearning/01-AI学习路线总览.md","filePath":"aiLearning/01-AI学习路线总览.md","lastUpdated":1780882022000}'),r={name:"aiLearning/01-AI学习路线总览.md"};function n(l,t,i,s,c,h){return e(),d("div",null,[...t[0]||(t[0]=[a(`<h1 id="ai-学习路线总览" tabindex="-1">AI 学习路线总览 <a class="header-anchor" href="#ai-学习路线总览" aria-label="Permalink to &quot;AI 学习路线总览&quot;">​</a></h1><p>这是一份从&quot;神经元怎么算&quot;到&quot;怎么搭一个能干活的 Agent&quot;的完整路线图。目标读者:<strong>有编程基础、想系统补齐 AI 知识</strong>的工程师。</p><blockquote><p>一句话先记住:今天的&quot;AI 应用&quot;,底下是 LLM,LLM 底下是 Transformer,Transformer 底下是神经网络,神经网络底下是矩阵乘法 + 求导。</p></blockquote><hr><h2 id="一、整套教程的结构" tabindex="-1">一、整套教程的结构 <a class="header-anchor" href="#一、整套教程的结构" aria-label="Permalink to &quot;一、整套教程的结构&quot;">​</a></h2><p>按&quot;从底到顶&quot;分六部分,<strong>前三部分讲原理(60%)、后三部分讲应用(40%)</strong>:</p><table tabindex="0"><thead><tr><th>部分</th><th>主题</th><th>你能搞清楚什么</th></tr></thead><tbody><tr><td>一、神经网络基础</td><td>数学、感知机、反向传播</td><td>一个神经网络是怎么&quot;学会&quot;东西的</td></tr><tr><td>二、经典架构</td><td>CNN、RNN、Embedding</td><td>为什么图像用 CNN、序列用 RNN,以及它们的局限</td></tr><tr><td>三、Transformer 与 LLM</td><td>Attention、GPT、训练范式</td><td>ChatGPT 的&quot;脑子&quot;长什么样</td></tr><tr><td>四、LLM 应用基本盘</td><td>Prompt、RAG、Tool Use</td><td>怎么让 LLM 干<strong>有用</strong>的活</td></tr><tr><td>五、Agent 与工作流</td><td>ReAct、多 Agent、编排</td><td>怎么让 LLM 自己<strong>规划+执行</strong>任务</td></tr><tr><td>六、工程实战</td><td>框架选型、评测、部署</td><td>真上线时要踩的坑</td></tr></tbody></table><hr><h2 id="二、完整目录-41-篇" tabindex="-1">二、完整目录(41 篇) <a class="header-anchor" href="#二、完整目录-41-篇" aria-label="Permalink to &quot;二、完整目录(41 篇)&quot;">​</a></h2><h3 id="第一部分-神经网络基础-原理打底" tabindex="-1">第一部分:神经网络基础(原理打底) <a class="header-anchor" href="#第一部分-神经网络基础-原理打底" aria-label="Permalink to &quot;第一部分:神经网络基础(原理打底)&quot;">​</a></h3><ul><li><code>02-数学预备-向量矩阵概率求导.md</code> —— 看懂论文需要的最低数学</li><li><code>03-从感知机到多层神经网络.md</code> —— 为什么&quot;叠层&quot;能解决异或</li><li><code>04-激活函数-为什么需要非线性.md</code> —— Sigmoid / ReLU / GELU 怎么选</li><li><code>05-损失函数-网络怎么知道自己错了.md</code> —— MSE、CrossEntropy、KL 散度</li><li><code>06-反向传播与梯度下降.md</code> —— 整个深度学习的引擎</li><li><code>07-训练技巧-过拟合归一化与初始化.md</code> —— Dropout、BatchNorm、Adam</li><li><code>08-PyTorch实操-手写一个分类器.md</code> —— 第一次跑通训练循环</li></ul><h3 id="第二部分-经典神经网络架构" tabindex="-1">第二部分:经典神经网络架构 <a class="header-anchor" href="#第二部分-经典神经网络架构" aria-label="Permalink to &quot;第二部分:经典神经网络架构&quot;">​</a></h3><ul><li><code>09-CNN卷积神经网络.md</code> —— 图像怎么&quot;看&quot;</li><li><code>10-RNN与LSTM循环神经网络.md</code> —— 序列建模的老办法</li><li><code>11-WordEmbedding词向量.md</code> —— 文字怎么变成数</li></ul><h3 id="第三部分-transformer-与大语言模型" tabindex="-1">第三部分:Transformer 与大语言模型 <a class="header-anchor" href="#第三部分-transformer-与大语言模型" aria-label="Permalink to &quot;第三部分:Transformer 与大语言模型&quot;">​</a></h3><ul><li><code>12-Attention注意力机制.md</code> —— Transformer 的灵魂</li><li><code>13-Transformer架构详解.md</code> —— Encoder / Decoder / 多头注意力</li><li><code>14-从GPT到LLM-自回归生成.md</code> —— 为什么&quot;下一个词预测&quot;能搞出智能</li><li><code>15-Tokenizer与BPE.md</code> —— 文字到 token 的桥</li><li><code>16-推理与采样-temperature-top-p-top-k.md</code> —— 模型&quot;创造力&quot;怎么调</li><li><code>17-预训练SFT与RLHF.md</code> —— 一个 LLM 是如何被&quot;调教&quot;出来的</li><li><code>18-LoRA与高效微调.md</code> —— 没有 8 张 A100 也能微调</li><li><code>19-ScalingLaw与涌现能力.md</code> —— 大力为什么能出奇迹</li></ul><h3 id="第四部分-llm-应用基本盘" tabindex="-1">第四部分:LLM 应用基本盘 <a class="header-anchor" href="#第四部分-llm-应用基本盘" aria-label="Permalink to &quot;第四部分:LLM 应用基本盘&quot;">​</a></h3><ul><li><code>20-PromptEngineering.md</code> —— Few-shot、CoT、Self-Consistency</li><li><code>21-FunctionCalling与ToolUse.md</code> —— 让模型会调 API</li><li><code>22-RAG检索增强生成.md</code> —— 给模型外挂&quot;知识库&quot;</li><li><code>23-Embedding与向量数据库.md</code> —— 语义检索的底层</li><li><code>24-ContextEngineering上下文工程.md</code> —— 比 Prompt Engineering 更上一层</li><li><code>25-Memory记忆系统.md</code> —— 短期/长期记忆怎么设计</li></ul><h3 id="第五部分-agent-与工作流" tabindex="-1">第五部分:Agent 与工作流 <a class="header-anchor" href="#第五部分-agent-与工作流" aria-label="Permalink to &quot;第五部分:Agent 与工作流&quot;">​</a></h3><ul><li><code>26-Agent入门-从ReAct说起.md</code> —— 第一个能&quot;自己想办法&quot;的 LLM</li><li><code>27-Agent架构模式.md</code> —— Plan-Execute、Reflection、Tree of Thoughts</li><li><code>28-多Agent协作.md</code> —— 角色分工、辩论、群聊模式</li><li><code>29-工作流编排-LangGraph与状态机.md</code> —— 把 Agent 装进可控流程</li><li><code>30-MCP协议.md</code> —— Anthropic 推的&quot;AI 应用插件标准&quot;</li></ul><h3 id="第六部分-工程实战" tabindex="-1">第六部分:工程实战 <a class="header-anchor" href="#第六部分-工程实战" aria-label="Permalink to &quot;第六部分:工程实战&quot;">​</a></h3><ul><li><code>31-框架选型对比.md</code> —— LangChain、LlamaIndex、Claude Agent SDK、AutoGen</li><li><code>32-Evaluation评测.md</code> —— 没有 eval 的 AI 项目都是耍流氓</li><li><code>33-部署与推理优化.md</code> —— 量化、KV Cache、vLLM、TensorRT</li><li><code>34-AI安全与对齐.md</code> —— Prompt Injection、Jailbreak、护栏</li><li><code>35-多模态简介.md</code> —— 视觉、语音、视频怎么接进来</li><li><code>36-实战-从零搭一个实用Agent.md</code> —— 把前面学的全用上</li></ul><h3 id="进阶补充-读完-36-之后的扩展线" tabindex="-1">进阶补充(读完 36 之后的扩展线) <a class="header-anchor" href="#进阶补充-读完-36-之后的扩展线" aria-label="Permalink to &quot;进阶补充(读完 36 之后的扩展线)&quot;">​</a></h3><ul><li><code>37-视觉模型-CLIP-Diffusion-SAM.md</code> —— VLM 之外另一条视觉主线</li><li><code>38-CodingAgent与ComputerUse.md</code> —— Cursor / Claude Code / Devin 怎么工作</li><li><code>39-LLMReasoning-o1与DeepSeekR1.md</code> —— &quot;推理模型&quot;范式与 GRPO</li><li><code>40-微调实战-QLoRA与Unsloth.md</code> —— 18 篇的实操配套,带你跑通</li><li><code>41-推理引擎深入-vLLM-SGLang-TensorRTLLM.md</code> —— 自部署的工程深水区</li></ul><hr><h2 id="三、不同背景的学习路径" tabindex="-1">三、不同背景的学习路径 <a class="header-anchor" href="#三、不同背景的学习路径" aria-label="Permalink to &quot;三、不同背景的学习路径&quot;">​</a></h2><h3 id="路径-a-工程师转-ai-最常见" tabindex="-1">路径 A:工程师转 AI(最常见) <a class="header-anchor" href="#路径-a-工程师转-ai-最常见" aria-label="Permalink to &quot;路径 A:工程师转 AI(最常见)&quot;">​</a></h3><p>你已经会写代码,目标是<strong>搞清楚 LLM/Agent 怎么工作</strong>,后续做 AI 产品。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>02 → 03 → 06 → 08    (原理打底,大概一周)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>12 → 13 → 14         (直奔 Transformer)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>20 → 21 → 22 → 26    (进入应用)</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>27 → 29 → 31 → 36    (Agent + 工程化)</span></span></code></pre></div><blockquote><p>跳过 09-11(CNN/RNN)是可以的,但读 13(Transformer)前<strong>必看 12(Attention)</strong>。</p></blockquote><h3 id="路径-b-想完整啃下来" tabindex="-1">路径 B:想完整啃下来 <a class="header-anchor" href="#路径-b-想完整啃下来" aria-label="Permalink to &quot;路径 B:想完整啃下来&quot;">​</a></h3><p>按顺序 02 → 36。预计 6-8 周(每天 1-2 小时)。</p><h3 id="路径-c-已经在用-llm-只想补原理" tabindex="-1">路径 C:已经在用 LLM,只想补原理 <a class="header-anchor" href="#路径-c-已经在用-llm-只想补原理" aria-label="Permalink to &quot;路径 C:已经在用 LLM,只想补原理&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>02 → 06        (数学+反向传播,知道梯度下降在干嘛)</span></span>
<span class="line"><span>12 → 13 → 14   (Attention + Transformer + 自回归)</span></span>
<span class="line"><span>17 → 18        (训练范式 + LoRA)</span></span></code></pre></div><p>预计 1-2 周,够你看懂大部分论文和技术博客。</p><h3 id="路径-d-只想当应用层调包侠-不推荐但可以" tabindex="-1">路径 D:只想当应用层调包侠(不推荐但可以) <a class="header-anchor" href="#路径-d-只想当应用层调包侠-不推荐但可以" aria-label="Permalink to &quot;路径 D:只想当应用层调包侠(不推荐但可以)&quot;">​</a></h3><p>直接 20 → 36。但<strong>强烈建议至少读完 12-14</strong>,否则你永远不知道为什么 LLM 会幻觉、为什么 context 会爆。</p><hr><h2 id="四、需要的前置知识" tabindex="-1">四、需要的前置知识 <a class="header-anchor" href="#四、需要的前置知识" aria-label="Permalink to &quot;四、需要的前置知识&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项</th><th>程度</th><th>不会怎么办</th></tr></thead><tbody><tr><td>Python</td><td>能写函数、用 class、装包</td><td>先学 Python 基础再回来</td></tr><tr><td>微积分</td><td>知道导数是斜率即可</td><td>02 篇会带你过一遍</td></tr><tr><td>线性代数</td><td>矩阵乘法、向量点积</td><td>02 篇会带你过一遍</td></tr><tr><td>概率</td><td>期望、条件概率</td><td>02 篇会带你过一遍</td></tr><tr><td>机器学习经典算法</td><td><strong>不需要</strong></td><td>直接深度学习,经典 ML 用到再补</td></tr></tbody></table><blockquote><p>不需要本科数学水平。<strong>你需要的是&quot;能看懂公式在表达什么&quot;</strong>,不是&quot;能徒手推导反向传播&quot;。</p></blockquote><hr><h2 id="五、推荐的工具链" tabindex="-1">五、推荐的工具链 <a class="header-anchor" href="#五、推荐的工具链" aria-label="Permalink to &quot;五、推荐的工具链&quot;">​</a></h2><table tabindex="0"><thead><tr><th>用途</th><th>工具</th><th>备注</th></tr></thead><tbody><tr><td>写代码</td><td>VSCode / Cursor</td><td>Cursor 写 AI 代码尤其顺</td></tr><tr><td>跑训练</td><td>Google Colab(免费 T4)</td><td>入门够用,本地有显卡更好</td></tr><tr><td>框架</td><td>PyTorch + HuggingFace</td><td>整个教程的主线</td></tr><tr><td>LLM API</td><td>Anthropic Claude / OpenAI</td><td>应用层都需要,Claude 推荐</td></tr><tr><td>向量库</td><td>Chroma(本地) / Pinecone(云)</td><td>22-23 篇会用</td></tr><tr><td>Agent 框架</td><td>Claude Agent SDK / LangGraph</td><td>26 篇之后会用</td></tr></tbody></table><hr><h2 id="六、给新手的几个忠告" tabindex="-1">六、给新手的几个忠告 <a class="header-anchor" href="#六、给新手的几个忠告" aria-label="Permalink to &quot;六、给新手的几个忠告&quot;">​</a></h2><ol><li><strong>不要从看论文开始</strong>。论文是给已经懂的人写的&quot;压缩包&quot;,新手看会怀疑人生。先把主线 36 篇过一遍,再按需要读 37-41 的进阶补充,最后回头读论文。</li><li><strong>必须动手跑代码</strong>。AI 不是看会的,是跑会的。每篇能跑的代码都 copy 下来跑一遍,改改超参数。</li><li><strong>先有&quot;全景图&quot;,再补细节</strong>。先快速过一遍路径 C,知道 Transformer 大概长什么样,再回来啃 06(反向传播)这种硬骨头会容易很多。</li><li><strong>&quot;原理&quot;和&quot;应用&quot;要交替学</strong>。只学原理会枯燥放弃,只学应用会浮在表面遇到问题不会解。</li><li><strong>对&quot;框架&quot;祛魅</strong>。LangChain、LlamaIndex 这些库本质都是 prompt + HTTP 请求 + 一点点状态管理。理解原理后,任何框架你都能 1 天上手。</li><li><strong>不要纠结&quot;哪个模型最好&quot;</strong>。GPT-5、Claude Opus 5、Gemini Ultra 几个月就换一茬,<strong>你要学的是能力,不是某个 API 的写法</strong>。</li></ol><hr><h2 id="七、本教程的风格约定" tabindex="-1">七、本教程的风格约定 <a class="header-anchor" href="#七、本教程的风格约定" aria-label="Permalink to &quot;七、本教程的风格约定&quot;">​</a></h2><ul><li><strong>代码用 Python</strong>(应用层会出现少量 TypeScript,因为前端集成时常用)</li><li><strong>每篇控制在 30 分钟读完</strong>,但需要你<strong>动手跑 30 分钟</strong>消化</li><li><strong>公式不躲也不堆</strong>:必要的写出来并用大白话解释,不必要的省掉</li><li><strong>优先讲&quot;为什么&quot;</strong>。光知道&quot;Transformer 用 Attention&quot;没用,要知道&quot;为什么 RNN 不够用、为什么 Attention 解决了它&quot;</li><li><strong>每篇末尾都有&quot;踩坑提醒&quot;或&quot;选型建议&quot;</strong>,帮你避免常见误区</li></ul><hr><h2 id="八、预计学习节奏" tabindex="-1">八、预计学习节奏 <a class="header-anchor" href="#八、预计学习节奏" aria-label="Permalink to &quot;八、预计学习节奏&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阶段</th><th>篇数</th><th>预计时间(每天 1-2 小时)</th></tr></thead><tbody><tr><td>神经网络基础(02-08)</td><td>7</td><td>7-10 天</td></tr><tr><td>经典架构(09-11)</td><td>3</td><td>3-5 天</td></tr><tr><td>Transformer 与 LLM(12-19)</td><td>8</td><td>10-14 天</td></tr><tr><td>LLM 应用(20-25)</td><td>6</td><td>7-10 天</td></tr><tr><td>Agent 与工作流(26-30)</td><td>5</td><td>7-10 天</td></tr><tr><td>工程实战(31-36)</td><td>6</td><td>10-14 天</td></tr><tr><td><strong>合计</strong></td><td><strong>35</strong></td><td><strong>6-9 周</strong></td></tr></tbody></table><blockquote><p>不要赶进度。<strong>第一遍 60% 理解就够了</strong>,做完一两个项目后回头再读一次,会发现理解深了一个量级。</p></blockquote><hr><p>下一篇:<code>02-数学预备:向量矩阵概率求导.md</code>,先把数学的最低门槛过了。</p>`,55)])])}const m=o(r,[["render",n]]);export{p as __pageData,m as default};
